const fs = require('fs');
const p = '03a2_Timeline_Dal_Live.html';
console.log('exists', fs.existsSync(p), 'size', fs.existsSync(p) ? fs.statSync(p).size : 0);
let html = fs.readFileSync('Index.html', 'utf8');
const re = /<\?\!\=\s+include\(['"](.*?)['"]\)[^>]*\?>/g;
let m, found = [];
while ((m = re.exec(html))) found.push(m[1]);
console.log('includes has 03a2', found.includes('03a2_Timeline_Dal_Live'));
console.log('near end', found.slice(-8));
const re2 = /include\('03a2[^']*'\)/;
console.log('raw match', html.match(re2));
